import React, { useState } from 'react';
import { toast } from 'react-toastify';
import api from '../utils/api';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

export default function CommunitySetup({ onSetupComplete }) {
  const [form, setForm] = useState({ name: '', description: '', category: 'Technology' });
  const [saving, setSaving] = useState(false);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await api.post('/communities/my/setup', form);
      toast.success('Community created successfully!');
      onSetupComplete(res.data.data);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to create community');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{
      minHeight: '60vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '32px 20px'
    }}>
      <div style={{ maxWidth: 520, width: '100%' }}>
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ fontSize: '4rem', marginBottom: '16px' }}>🏛️</div>
          <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '1.75rem', marginBottom: '12px' }}>
            SET UP YOUR <span className="gradient-text">COMMUNITY</span>
          </h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.95rem', lineHeight: '1.6' }}>
            Your account is approved but no community is linked yet. Create your community to get started.
          </p>
        </div>

        <div className="card" style={{ padding: '32px' }}>
          <form onSubmit={handleSubmit}>
            <div className="form-group" style={{ marginBottom: '20px' }}>
              <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
                Community Name *
              </label>
              <input
                className="form-control"
                value={form.name}
                onChange={e => set('name', e.target.value)}
                placeholder="Enter your community name"
                required
                style={{ padding: '12px' }}
              />
            </div>

            <div className="form-group" style={{ marginBottom: '20px' }}>
              <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
                Category *
              </label>
              <select
                className="form-control"
                value={form.category}
                onChange={e => set('category', e.target.value)}
                style={{ padding: '12px' }}
              >
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div className="form-group" style={{ marginBottom: '28px' }}>
              <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
                Description *
              </label>
              <textarea
                className="form-control"
                rows={4}
                value={form.description}
                onChange={e => set('description', e.target.value)}
                placeholder="Describe your community's purpose and activities..."
                required
                style={{ padding: '12px', resize: 'vertical' }}
              />
            </div>

            <button
              type="submit"
              className="btn btn-primary"
              disabled={saving}
              style={{ width: '100%', justifyContent: 'center', padding: '14px' }}
            >
              {saving ? (
                <span style={{ display: 'flex', alignItems: 'center', gap: '8px', justifyContent: 'center' }}>
                  <span className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }} />
                  Creating...
                </span>
              ) : '🚀 Create Community'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
